import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Home() {
  const navigate = useNavigate();

  // 🔒 Protect Home Page
  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isLoggedIn");

    if (!isLoggedIn) {
      navigate("/login");
    }
  }, []);

  return (
    <div style={styles.container}>

      {/* Navbar */}
      <Navbar />

      {/* Main Section */}
      <div style={styles.main}>
        <div style={styles.card}>

          <h1 style={styles.title}>Welcome to DocBook 🏥</h1>
          <p style={styles.subtitle}>
            Book appointments easily with experienced doctors and manage your health in one place.
          </p>

          {/* Dashboard Cards */}
          <div style={styles.grid}>

            <div style={styles.box}>
              <h3>👨‍⚕️ Doctors</h3>
              <p>Find specialists near you</p>
            </div>

            <div style={styles.box}>
              <h3>📅 Appointments</h3>
              <p>View & manage bookings</p>
            </div>

            <div style={styles.box}>
              <h3>💊 Health Tips</h3>
              <p>Daily health updates</p>
            </div>

          </div>

        </div>
      </div>

      {/* Footer */}
      <Footer />

    </div>
  );
}

export default Home;

// Styles
const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    backgroundColor: "#f4f6f9",
    padding: "20px"
  },

  card: {
    backgroundColor: "white",
    padding: "40px",
    borderRadius: "10px",
    textAlign: "center",
    width: "600px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
  },

  title: {
    marginBottom: "10px",
    color: "#2c3e50"
  },

  subtitle: {
    color: "#555",
    marginBottom: "25px"
  },

  grid: {
    display: "flex",
    gap: "15px",
    justifyContent: "center",
    flexWrap: "wrap",
    marginTop: "10px"
  },

  box: {
    backgroundColor: "#f9f9f9",
    padding: "15px",
    borderRadius: "8px",
    width: "160px",
    boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
    textAlign: "center"
  }
};
